## Step 4: Wire API Hooks

If your page fetches data from the API, create hooks in the centralized hooks directory.

### Hook File Locations

| App | Hooks Directory |
|-----|----------------|
| smithy-web | `apps/smithy-web/src/api/hooks/` |
| quarry-web | `apps/quarry-web/src/api/hooks/` |

### 4a. Create the Hook File

```typescript
// apps/{app}/src/api/hooks/useMyFeature.ts
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

const API_BASE = import.meta.env.VITE_API_URL || '';

// Query key factory for cache management
export const myFeatureKeys = {
  all: ['my-feature'] as const,
  list: (filter?: MyFeatureFilter) => [...myFeatureKeys.all, 'list', filter] as const,
  detail: (id: string) => [...myFeatureKeys.all, 'detail', id] as const,
};

// Fetch function
async function fetchMyFeatures(filter?: MyFeatureFilter) {
  const params = new URLSearchParams();
  if (filter?.status) params.set('status', filter.status);
  if (filter?.limit) params.set('limit', String(filter.limit));

  const res = await fetch(`${API_BASE}/api/my-feature?${params}`);
  if (!res.ok) throw new Error('Failed to fetch');
  return res.json();
}

// Query hook
export function useMyFeatures(filter?: MyFeatureFilter) {
  return useQuery({
    queryKey: myFeatureKeys.list(filter),
    queryFn: () => fetchMyFeatures(filter),
    staleTime: 30_000,
    refetchOnWindowFocus: true,
  });
}

// Mutation hook
export function useCreateMyFeature() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (data: CreateMyFeatureInput) => {
      const res = await fetch(`${API_BASE}/api/my-feature`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
      if (!res.ok) throw new Error('Failed to create');
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: myFeatureKeys.all });
    },
  });
}
```

### 4b. Export from Index

```typescript
// apps/{app}/src/api/hooks/index.ts
export * from './useMyFeature';
```

> **Note:** `smithy-web` uses barrel re-exports (`api/hooks/index.ts`). `quarry-web` does not have a barrel file — import hooks directly by path (e.g., `import { useMyFeatures } from '../api/hooks/useMyFeature'`).

### 4c. Add Types (if needed)

```typescript
// apps/{app}/src/api/types.ts
export interface MyFeatureFilter {
  status?: string;
  limit?: number;
}

export interface CreateMyFeatureInput {
  title: string;
  description?: string;
}
```

> **Note:** `smithy-web` has a centralized `api/types.ts`. `quarry-web` co-locates types with route-specific files (e.g., `routes/{page-name}/types.ts`) — add your types there instead.

### 4d. Add Real-Time Updates (Optional)

Use the `useRealtimeEvents` hook to invalidate queries when data changes via WebSocket:

```typescript
import { useRealtimeEvents } from '../../api/hooks/useRealtimeEvents';

function MyFeaturePage() {
  useRealtimeEvents({
    channels: ['tasks'], // Channel names are strings: 'tasks', 'documents', 'entities', '*' (default), etc.
    onEvent: (event) => {
      // React Query caches are automatically invalidated
      // via the defaultQueryKeyMapper in useRealtimeEvents
    },
  });

  // ... rest of component
}
```

## Step 5: Add Search Param Validation

Search params let users bookmark and share filtered views. The `validateSearch` function in the route definition ensures type safety.

### Common Patterns

```typescript
validateSearch: (search: Record<string, unknown>) => {
  return {
    // String param (optional)
    selected: typeof search.selected === 'string' ? search.selected : undefined,

    // String param with default
    tab: typeof search.tab === 'string' ? search.tab : 'overview',

    // Number param with default
    page: typeof search.page === 'number' ? search.page :
          typeof search.page === 'string' ? parseInt(search.page, 10) || 1 : 1,

    // Boolean param
    readyOnly: search.readyOnly === true || search.readyOnly === 'true',

    // Enum param
    status: ['active', 'completed', 'archived'].includes(search.status as string)
      ? (search.status as string) : undefined,
  };
},
```

